SELECT 
FROM notice n
LEFT JOIN sys_user u ON n.publisher_id = u.id
WHERE n.is_deleted = 0

    AND n.title LIKE CONCAT('%', #{title}, '%')


    AND n.type = #{type}


    AND n.status = #{status}

ORDER BY n.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM notice n
WHERE n.is_deleted = 0

    AND n.title LIKE CONCAT('%', #{title}, '%')


    AND n.type = #{type}


    AND n.status = #{status}
